/**
 * @name PreflightAssetsResource confirmed path traversal - no validation
 * @description User-controlled filename query param flows to getResource with no path validation whatsoever
 * @kind path-problem
 * @problem.severity error
 * @id java/preflight-confirmed-path-traversal
 * @tags security external/cwe/cwe-022 external/cwe/cwe-073
 */

import java
import semmle.code.java.dataflow.TaintTracking
import semmle.code.java.dataflow.FlowSources

module PreflightTraversalConfig implements DataFlow::ConfigSig {
  predicate isSource(DataFlow::Node source) {
    source instanceof RemoteFlowSource
  }

  predicate isSink(DataFlow::Node sink) {
    exists(MethodCall mc |
      mc.getMethod().hasName("getResource") and
      mc.getEnclosingCallable().getDeclaringType().getName() = "PreflightAssetsResource"
    |
      sink.asExpr() = mc.getAnArgument()
    )
  }

  // No barriers - we expect no sanitization
}

module PreflightTraversalFlow = TaintTracking::Global<PreflightTraversalConfig>;
import PreflightTraversalFlow::PathGraph

from PreflightTraversalFlow::PathNode source, PreflightTraversalFlow::PathNode sink
where PreflightTraversalFlow::flowPath(source, sink)
select sink.getNode(), source, sink,
  "CONFIRMED: User-controlled input from $@ flows to Class.getResource() in PreflightAssetsResource with NO path validation - allows classpath traversal to access WEB-INF/, sensitive configs etc.",
  source.getNode(), "HTTP request parameter"

/**
 * @name Final sweep - all HTTP input to getResource flows in the codebase
 * @description Comprehensive check for all paths from HTTP input to ClassLoader.getResource
 * @kind path-problem
 * @problem.severity error
 * @id java/all-http-to-getresource
 * @tags security external/cwe/cwe-022
 */

import java
import semmle.code.java.dataflow.TaintTracking
import semmle.code.java.dataflow.FlowSources

module AllGetResourceConfig implements DataFlow::ConfigSig {
  predicate isSource(DataFlow::Node source) {
    source instanceof RemoteFlowSource
  }

  predicate isSink(DataFlow::Node sink) {
    exists(MethodCall mc |
      mc.getMethod().hasName("getResource") or
      mc.getMethod().hasName("getResourceAsStream")
    |
      sink.asExpr() = mc.getAnArgument()
    )
  }

  // Exclude flows through well-known safe classes
  predicate isBarrier(DataFlow::Node node) {
    // Known safe: AllowedAuxiliaryPathChecker uses Path.startsWith
    node.getEnclosingCallable().getDeclaringType().getName() = "AllowedAuxiliaryPathChecker"
  }
}

module AllGetResourceFlow = TaintTracking::Global<AllGetResourceConfig>;
import AllGetResourceFlow::PathGraph

from AllGetResourceFlow::PathNode source, AllGetResourceFlow::PathNode sink
where AllGetResourceFlow::flowPath(source, sink)
select sink.getNode(), source, sink,
  "HTTP input from $@ flows to getResource() in " +
  sink.getNode().getEnclosingCallable().getDeclaringType().getName(),
  source.getNode(), "HTTP request"
